patch:
diff --git a/llvm/lib/Analysis/LoopAccessAnalysis.cpp b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
index cf3bb6a8eae1..bdb533720b9e 100644
--- a/llvm/lib/Analysis/LoopAccessAnalysis.cpp
+++ b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
@@ -547,6 +547,14 @@ void RuntimePointerChecking::groupChecks(
           if (TotalComparisons > MemoryCheckMergeThreshold)
             break;

+          // Ensure we only attempt to merge pointers into groups with the same
+          // address space. Mixing address spaces violates the invariant in
+          // RuntimeCheckingPtrGroup::addPointer and can cause an assertion.
+          unsigned PtrAS =
+              Pointers[Pointer].PointerValue->getType()->getPointerAddressSpace();
+          if (Group.AddressSpace != PtrAS)
+            continue;
+
           TotalComparisons++;

           if (Group.addPointer(Pointer, *this)) {
@@ -1189,6 +1197,26 @@ bool AccessAnalysis::canCheckPtrAtRT(
   bool CanDoRT = true;

   bool MayNeedRTCheck = false;
+  // Even if we don't need to perform full runtime check analysis, bail out if
+  // we would need to compare pointers from different address spaces within the
+  // same alias set. Such comparisons are not well-defined for building bounds
+  // checks and should be reported as unknown array bounds.
+  for (const auto &AS : AST) {
+    auto ASPointers = AS.getPointers();
+    for (unsigned i = 0; i < ASPointers.size(); ++i) {
+      const Value *PiC = ASPointers[i];
+      unsigned ASi = PiC->getType()->getPointerAddressSpace();
+      for (unsigned j = i + 1; j < ASPointers.size(); ++j) {
+        const Value *PjC = ASPointers[j];
+        unsigned ASj = PjC->getType()->getPointerAddressSpace();
+        if (ASi != ASj) {
+          UncomputablePtr = const_cast<Value *>(PiC);
+          return false;
+        }
+      }
+    }
+  }
+
   if (!IsRTCheckAnalysisNeeded) return true;

   bool IsDepCheckNeeded = isDependencyCheckNeeded();
@@ -1311,6 +1339,9 @@ bool AccessAnalysis::canCheckPtrAtRT(
         LLVM_DEBUG(
             dbgs() << "LAA: Runtime check would require comparison between"
                       " different address spaces\n");
+        // Indicate to the caller that we couldn't identify array bounds for
+        // at least one of the pointers involved in the comparison.
+        UncomputablePtr = PtrI;
         return false;
       }
     }

